Sample Explorer


Code
db = DuckDBClient.of({
  samples: FileAttachment("data/samples.parquet"),
  judgments: FileAttachment("data/judgments.parquet")
})









Code
viewof selectedModel = Inputs.select(
  ["All", "Qwen2.5-7B-Instruct", "Llama-3.1-8B-Instruct", "gemma-3-4b-it"],
  {label: "Model", value: "All"}
)

viewof selectedPersona = Inputs.select(
  ["All", "sarcasm", "misalignment", "goodness"],
  {label: "Persona", value: "All"}
)

viewof selectedCondition = Inputs.select(
  ["All", "base", "sarcasm", "misalignment", "goodness"],
  {label: "Condition", value: "All"}
)

viewof selectedCoeff = Inputs.select(
  ["All", "-5.0", "0.0", "5.0"],
  {label: "Coefficient", value: "All"}
)

viewof minPersonaStrength = Inputs.range(
  [0, 10], {label: "Min Persona Strength", step: 1, value: 0}
)

viewof minCompliance = Inputs.range(
  [0, 10], {label: "Min Assistant Compliance", step: 1, value: 0}
)

viewof minCoherence = Inputs.range(
  [0, 10], {label: "Min Coherence", step: 1, value: 0}
)





















































Code
viewof redraw = Inputs.button("Draw 10 new samples")









Code
filteredSamples = {
  redraw;
  let where = [];
  if (selectedModel !== "All") where.push(`s.model = '${selectedModel}'`);
  if (selectedPersona !== "All") where.push(`s.persona = '${selectedPersona}'`);
  if (selectedCondition !== "All") where.push(`s.condition = '${selectedCondition}'`);
  if (selectedCoeff !== "All") where.push(`s.coefficient = ${selectedCoeff}`);
  if (minPersonaStrength &gt; 0) where.push(`j.persona_strength &gt;= ${minPersonaStrength}`);
  if (minCompliance &gt; 0) where.push(`j.assistant_compliance &gt;= ${minCompliance}`);
  if (minCoherence &gt; 0) where.push(`j.coherence &gt;= ${minCoherence}`);

  let whereClause = where.length &gt; 0 ? `WHERE ${where.join(" AND ")}` : "";
  return db.query(`
    SELECT s.*, j.persona_strength, j.assistant_compliance, j.coherence
    FROM samples s
    LEFT JOIN judgments j
      ON s.model = j.model AND s.persona = j.persona AND s.condition = j.condition
      AND s.coefficient = j.coefficient AND s.trait = j.trait AND s.user_prompt = j.user_prompt
      AND s.source = j.source
    ${whereClause}
    ORDER BY RANDOM() LIMIT 10
  `);
}









Code
html`&lt;p&gt;&lt;strong&gt;${filteredSamples.length}&lt;/strong&gt; samples shown (random subset)&lt;/p&gt;`









