Code
viewof cmpModelShared = cmpLinkModel
  ? Inputs.select(cmpModels, {label: "Model", value: "All"})
  : Inputs.form({a: Inputs.select(cmpModels, {label: "Model A", value: "All"}), b: Inputs.select(cmpModels, {label: "Model B", value: "All"})})

viewof cmpPersonaShared = cmpLinkPersona
  ? Inputs.select(cmpPersonas, {label: "Persona", value: "All"})
  : Inputs.form({a: Inputs.select(cmpPersonas, {label: "Persona A", value: "All"}), b: Inputs.select(cmpPersonas, {label: "Persona B", value: "All"})})

viewof cmpConditionShared = cmpLinkCondition
  ? Inputs.select(cmpConditions, {label: "Condition", value: "All"})
  : Inputs.form({a: Inputs.select(cmpConditions, {label: "Condition A", value: "All"}), b: Inputs.select(cmpConditions, {label: "Condition B", value: "All"})})

viewof cmpCoeffShared = cmpLinkCoeff
  ? Inputs.select(cmpCoeffs, {label: "Coefficient", value: "All"})
  : Inputs.form({a: Inputs.select(cmpCoeffs, {label: "Coeff A", value: "All"}), b: Inputs.select(cmpCoeffs, {label: "Coeff B", value: "All"})})
































Code
cmpFilterA = ({
  model: cmpLinkModel ? cmpModelShared : cmpModelShared.a,
  persona: cmpLinkPersona ? cmpPersonaShared : cmpPersonaShared.a,
  condition: cmpLinkCondition ? cmpConditionShared : cmpConditionShared.a,
  coefficient: cmpLinkCoeff ? cmpCoeffShared : cmpCoeffShared.a
})

cmpFilterB = ({
  model: cmpLinkModel ? cmpModelShared : cmpModelShared.b,
  persona: cmpLinkPersona ? cmpPersonaShared : cmpPersonaShared.b,
  condition: cmpLinkCondition ? cmpConditionShared : cmpConditionShared.b,
  coefficient: cmpLinkCoeff ? cmpCoeffShared : cmpCoeffShared.b
})


















Code
viewof cmpRedraw = Inputs.button("Draw comparison")









