cmpResult = {
  cmpRedraw;
  function buildWhere(f) {
    let w = [];
    if (f.model !== "All") w.push(`s.model = '${f.model}'`);
    if (f.persona !== "All") w.push(`s.persona = '${f.persona}'`);
    if (f.condition !== "All") w.push(`s.condition = '${f.condition}'`);
    if (f.coefficient !== "All") w.push(`s.coefficient = ${f.coefficient}`);
    return w;
  }

  const wA = buildWhere(cmpFilterA);
  const wB = buildWhere(cmpFilterB);

  const whereA = wA.length &gt; 0 ? `WHERE ${wA.join(" AND ")}` : "";
  const whereB = wB.length &gt; 0 ? `WHERE ${wB.join(" AND ")}` : "";

  const poolA = await db.query(`
    SELECT s.*, j.persona_strength, j.assistant_compliance, j.coherence
    FROM samples s
    LEFT JOIN judgments j
      ON s.model = j.model AND s.persona = j.persona AND s.condition = j.condition
      AND s.coefficient = j.coefficient AND s.trait = j.trait AND s.user_prompt = j.user_prompt
      AND s.source = j.source
    ${whereA}
  `);

  const poolB = await db.query(`
    SELECT s.*, j.persona_strength, j.assistant_compliance, j.coherence
    FROM samples s
    LEFT JOIN judgments j
      ON s.model = j.model AND s.persona = j.persona AND s.condition = j.condition
      AND s.coefficient = j.coefficient AND s.trait = j.trait AND s.user_prompt = j.user_prompt
      AND s.source = j.source
    ${whereB}
  `);

  const promptsB = new Set(poolB.map(d =&gt; d.user_prompt));
  const candidates = poolA.filter(d =&gt; promptsB.has(d.user_prompt));

  if (candidates.length === 0) return {prompt: null, a: null, b: null};

  const pick = candidates[Math.floor(Math.random() * candidates.length)];
  const matchesB = poolB.filter(d =&gt; d.user_prompt === pick.user_prompt);
  const pickB = matchesB[Math.floor(Math.random() * matchesB.length)];

  return {prompt: pick.user_prompt, a: pick, b: pickB};
}









