{
  if (cmpResult.prompt === null) {
    return html`&lt;p style="color: #d32f2f;"&gt;&lt;strong&gt;No overlapping prompts found for these filter combinations.&lt;/strong&gt;&lt;/p&gt;`;
  }

  const d = cmpResult;

  function scoreRow(s) {
    if (s.persona_strength == null) return "";
    return html`
      &lt;div style="display: flex; gap: 10px; font-size: 0.8em; margin-top: 4px;"&gt;
        &lt;span style="color: #d32f2f;"&gt;&lt;strong&gt;P:&lt;/strong&gt; ${s.persona_strength}/10&lt;/span&gt;
        &lt;span style="color: #1976d2;"&gt;&lt;strong&gt;C:&lt;/strong&gt; ${s.assistant_compliance}/10&lt;/span&gt;
        &lt;span style="color: #388e3c;"&gt;&lt;strong&gt;H:&lt;/strong&gt; ${s.coherence}/10&lt;/span&gt;
      &lt;/div&gt;
    `;
  }

  function metaRow(s) {
    return html`
      &lt;div style="font-size: 0.8em; color: #666;"&gt;
        &lt;strong&gt;${s.model}&lt;/strong&gt; · ${s.condition} · coeff ${s.coefficient}
      &lt;/div&gt;
    `;
  }

  const container = html`
    &lt;div&gt;
      &lt;div style="background: #e3f2fd; padding: 8px 12px; border-radius: 6px; margin-bottom: 10px;"&gt;
        &lt;strong&gt;Prompt:&lt;/strong&gt; ${d.prompt}
      &lt;/div&gt;
      &lt;div style="display: grid; grid-template-columns: 1fr 1fr; gap: 12px;"&gt;
        &lt;div style="border: 2px solid #1976d2; border-radius: 6px; padding: 10px; background: #fafafa;"&gt;
          &lt;div style="font-weight: bold; color: #1976d2; margin-bottom: 6px;"&gt;A&lt;/div&gt;
          ${metaRow(d.a)}
          ${scoreRow(d.a)}
          &lt;div class="cmp-response" style="background: white; padding: 8px; border-radius: 4px; border: 1px solid #eee; margin-top: 8px; max-height: 200px; overflow: hidden; cursor: pointer;"&gt;
            ${d.a.response}
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div style="border: 2px solid #d32f2f; border-radius: 6px; padding: 10px; background: #fafafa;"&gt;
          &lt;div style="font-weight: bold; color: #d32f2f; margin-bottom: 6px;"&gt;B&lt;/div&gt;
          ${metaRow(d.b)}
          ${scoreRow(d.b)}
          &lt;div class="cmp-response" style="background: white; padding: 8px; border-radius: 4px; border: 1px solid #eee; margin-top: 8px; max-height: 200px; overflow: hidden; cursor: pointer;"&gt;
            ${d.b.response}
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  `;

  container.querySelectorAll(".cmp-response").forEach(el =&gt; {
    el.addEventListener("click", () =&gt; {
      el.style.maxHeight = el.style.maxHeight === "none" ? "200px" : "none";
    });
  });

  return container;
}
